in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
out vec4 color;
out vec2 uv0;
vec4 vert() {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
  #endif
  #if USE_PIXEL_ALIGNMENT
    pos = cc_matView * pos;
    pos.xyz = floor(pos.xyz);
    pos = cc_matProj * pos;
  #else
    pos = cc_matViewProj * pos;
  #endif
  uv0 = a_texCoord;
  #if SAMPLE_FROM_RT
    uv0 = cc_cameraPos.w > 1.0 ? vec2(uv0.x, 1.0 - uv0.y) : uv0;
  #endif
  color = a_color;
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision highp float;
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
in vec4 color;
#if USE_TEXTURE
  in vec2 uv0;
  uniform sampler2D cc_spriteTexture;
#endif
layout(std140) uniform Param {
  vec4 UVOffset;
  vec4 lightColor;
  float rotated;
  float lightWidth;
  float speedRate;
  float slopingRate;
  float speedFrequen;
  float lightPosi;
  float lightDis;
  int isVerticle;
};
float getRate(vec4 convertData) {
  vec2 convertUV = vec2(convertData.x, convertData.y);
  vec2 convertRate = vec2(convertData.z, convertData.w);
  float rate = 0.0;
  float comparePosi = convertUV.x + convertUV.y * slopingRate;
  if (isVerticle == 1) {
    comparePosi = convertUV.y + convertUV.x * slopingRate;
  }
  float position = -speedFrequen + 2.0 * speedFrequen * fract(speedRate * lightDis / speedFrequen);
  float from = position - lightWidth / 2.0;
  float to = position + lightWidth / 2.0;
  if (comparePosi > from && comparePosi < to) {
    if (comparePosi >= position) {
      rate = smoothstep(to, position, comparePosi);
    } else {
      rate = smoothstep(from, position , comparePosi);
    }
  }
  return rate;
}
vec4 getConvertUV() {
  vec2 convertUV;
  vec2 convertRate;
  convertRate.x = UVOffset.z - UVOffset.x;
  convertRate.y = UVOffset.w - UVOffset.y;
  convertUV.x = (uv0.x - UVOffset.x) / convertRate.x;
  convertUV.y = (uv0.y - UVOffset.y) / convertRate.y;
  convertRate.x = abs(convertRate.x);
  convertRate.y = abs(convertRate.y);
  if (rotated > 0.5) {
    float temp = convertUV.x;
    convertUV.x = convertUV.y;
    convertUV.y = 1.0 - temp;
    temp = convertRate.x;
    convertRate.x = convertRate.y;
    convertRate.y = temp;
  }
  return vec4(convertUV, convertRate);
}
vec4 frag() {
  vec4 o = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
    o *= CCSampleWithAlphaSeparated(cc_spriteTexture, uv0);
    #if IS_GRAY
      float gray = 0.2126 * o.r + 0.7152 * o.g + 0.0722 * o.b;
      o.r = o.g = o.b = gray;
    #endif
  #endif
  o *= color;
  ALPHA_TEST(o);
  float rate = getRate(getConvertUV());
  if (rate > 0.0) {
    vec3 improve = 0.008 * max(o.r + o.g + o.b, 0.5) * vec3(255.0 * lightColor.x, 255.0 * lightColor.y, 255.0 * lightColor.z);
    vec3 result = improve * vec3(o.r, o.g, o.b);
    vec4 dstColor = vec4(result, o.a);
    o = o + rate * (dstColor - o);
  }
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

